#!/usr/bin/env node
// Wire "Run/Edit" toolbars into the GENERATED LZX reference pages (docs/reference/*.html),
// the same way build-docs.mjs does for the developers/deployers guides.
//
// WHY a post-pass (not the same path as build-docs): the reference is NOT built by the
// DocBook chunker — it is generated by build-reference.sh (js2doc → refguide-multi.xsl →
// split-reference.mjs), which writes the per-class pages. The example code in those pages is
// inline doc-comment LZX rendered as <pre class="example"> / <pre><code> blocks (no separate
// .lzx files, no <example role="live-example"> markup). The original 4.9 reference embedded
// each <canvas>-rooted example as a running DHTML app (common-html.xsl, lzt=html&lzr=dhtml),
// so attaching a Run button is faithful to the original — not invented UI.
//
// This pass:
//   - finds every <pre class="example"> / <pre><code> block that is a full <canvas> app,
//   - COMPILE-GATES it with the distro's own in-browser compiler (skips non-compiling /
//     unsupported / resource-needing fragments — exactly build-docs' gate),
//   - strips the copyright footer + the on-canvas debugger from the staged copy,
//   - stages it as docs/reference/programs/<key>-<n>.lzx,
//   - injects the SAME liveWidget/lzRun toolbar + iframe runner build-docs emits.
//
// Idempotent: prior injected widgets + the lzRun <script> are stripped before re-injecting,
// so it is safe to re-run over already-wired pages. build-reference.sh calls it as its last
// step (split-reference.mjs has just written fresh, un-wired pages); it can also be run
// standalone over the committed docs/reference/*.html:  node wire-reference-examples.mjs
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const HERE = path.dirname(fileURLToPath(import.meta.url));         // docs/src/reference
const OUT = path.resolve(HERE, "../../reference");                 // docs/reference (generated)
const DISTRO = path.resolve(HERE, "../../..");                     // openlaszlo-5.0
const PROGRAMS = path.join(OUT, "programs");

// ---- compile gate (identical setup to build-docs.mjs) --------------------
let validateCompile = null;   // (source, probePath) => boolean
try {
  const { compile } = await import(path.join(DISTRO, "compiler/dist/compile.js"));
  const { nodeOptions } = await import(path.join(DISTRO, "compiler/dist/node-io.js"));
  const runtime = path.join(DISTRO, "runtime");
  const lpsHome = fs.mkdtempSync("/tmp/oldoc-ref-lps-");
  fs.symlinkSync(runtime, path.join(lpsHome, "lps"));
  fs.mkdirSync(path.join(lpsHome, "WEB-INF/lps/misc"), { recursive: true });
  fs.symlinkSync(path.join(runtime, "lzx-autoincludes.properties"),
    path.join(lpsHome, "WEB-INF/lps/misc/lzx-autoincludes.properties"));
  validateCompile = (source, probePath) => {
    try {
      const res = compile(source, { ...nodeOptions(probePath, lpsHome), proxied: false, sprites: "none" });
      return !res.unsupported;
    } catch { return false; }   // parse / unresolved / refuse → not runnable
  };
} catch (e) {
  console.warn("  (reference compile validation skipped: " + (e && e.message || e) + ")");
}

// ---- helpers (mirrors build-docs.mjs) ------------------------------------
const decodeEnt = s => s
  .replace(/&lt;/g, "<").replace(/&gt;/g, ">").replace(/&quot;/g, '"')
  .replace(/&#0*39;/g, "'").replace(/&apos;/g, "'").replace(/&#0*160;/g, " ").replace(/ /g, " ")
  .replace(/&amp;/g, "&");

const stripCopyright = s => s
  .replace(/\s*(?:<|&lt;)!--[\s\S]*?X_LZ_COPYRIGHT_BEGIN[\s\S]*?X_LZ_COPYRIGHT_END[\s\S]*?--(?:>|&gt;)/gi, "")
  .replace(/\s*(?:<|&lt;)!--\s*@LZX_VERSION@[\s\S]*?--(?:>|&gt;)/gi, "");

// Doc embeds run debug-OFF (the distro ships the production runtime, no on-canvas debugger).
const stripDebug = s => s
  .replace(/<debug\b[^>]*\/>/g, "")
  .replace(/<debug\b[^>]*>[\s\S]*?<\/debug>/g, "")
  .replace(/(<canvas\b[^>]*?)\s+debug\s*=\s*(["'])(?:true|TRUE)\2/g, "$1");

const canvasHeight = s => {
  const m = /<canvas\b[^>]*?\bheight\s*=\s*["'](\d+)(?:px)?["']/i.exec(s);
  return m ? Math.max(96, Math.min(620, +m[1])) : null;
};
const usesDebug = s => /<debug\b/.test(s) || /\bdebug\s*=\s*(["'])true\1/i.test(s);

const liveWidget = (url, height, isDebug) =>
  `<div class="live-example"><div class="live-toolbar">` +
  `<button class="live-run" type="button" data-run="${url}"${height ? ` data-height="${height}"` : ""}${isDebug ? ` data-debug="1"` : ""} onclick="lzRun(this)">&#9654;&#xfe0e; Run</button>` +
  `<a class="live-edit" href="${url}?edit" target="_blank" rel="noopener">&#9998;&#xfe0e; Edit</a>` +
  `</div></div>`;
const liveScript =
  `<script>function lzRun(b){var d=b.parentNode.parentNode,f=d.querySelector('iframe.live-frame');` +
  `if(!f){f=document.createElement('iframe');f.className='live-frame';f.title='live example';` +
  `var h=b.getAttribute('data-height');if(h)f.style.height=h+'px';` +
  `d.appendChild(f);b.innerHTML='&#8635;&#xfe0e; Reload';}` +
  `var u=b.getAttribute('data-run');if(b.getAttribute('data-debug'))u+=(u.indexOf('?')<0?'?':'&')+'debug=true';f.src=u;}</script>`;

// strip any previously-injected widgets/script so re-runs are clean (idempotent)
const unwire = h => h
  .replace(/<div class="live-example"><div class="live-toolbar">[\s\S]*?<\/div><\/div>/g, "")
  .replace(/<script>function lzRun\(b\)\{[\s\S]*?<\/script>/g, "");

// the <pre> example forms emitted by refguide-multi.xsl
const PRE_RE = /<pre class="example">([\s\S]*?)<\/pre>|<pre><code>([\s\S]*?)<\/code><\/pre>/g;

// ---- live-example CSS into ref.css (once) --------------------------------
const refCss = path.join(OUT, "ref.css");
if (fs.existsSync(refCss)) {
  let css = fs.readFileSync(refCss, "utf8");
  if (!/\.live-example\{/.test(css)) {
    css += `
.live-example{margin:-4px 0 18px}
.live-toolbar{display:flex;gap:8px;align-items:center;background:#eef1f7;border:1px solid #d4dae8;border-top:0;border-radius:0 0 4px 4px;padding:6px 10px}
.live-run,.live-edit{font:12px/1 -apple-system,Helvetica,Arial,sans-serif;padding:5px 12px;border-radius:3px;border:1px solid;cursor:pointer;text-decoration:none}
.live-run{background:#3f6fd1;color:#fff;border-color:#3f6fd1}
.live-run:hover{background:#4f7fe0}
.live-edit{background:#fff;color:#36488f;border-color:#c2cbe0}
.live-edit:hover{background:#f4f7ff;text-decoration:underline}
.live-frame{display:block;width:100%;height:240px;margin-top:8px;border:1px solid #d4dae8;border-radius:4px;background:#fff}
`;
    fs.writeFileSync(refCss, css);
  }
}

// ---- process pages -------------------------------------------------------
fs.mkdirSync(PROGRAMS, { recursive: true });
let pagesWired = 0, examplesWired = 0, candidates = 0, skipped = 0;
const stagedNames = new Set();

for (const f of fs.readdirSync(OUT)) {
  if (!f.endsWith(".html") || f === "index.html") continue;
  const fp = path.join(OUT, f);
  const key = f.replace(/\.html$/, "");
  let h = unwire(fs.readFileSync(fp, "utf8"));
  let idx = 0, injected = 0;

  h = h.replace(PRE_RE, (full, exBody, codeBody) => {
    const isCode = codeBody !== undefined;
    const innerRaw = isCode ? codeBody : exBody;
    const source = stripCopyright(decodeEnt(innerRaw)).trim();
    if (!/<canvas[\s>/]/.test(source)) return full;   // only full <canvas> apps are runnable
    candidates++;
    const name = `${key}-${++idx}.lzx`;
    const probe = path.join(PROGRAMS, name);
    if (validateCompile && !validateCompile(source, probe)) { skipped++; return full; }  // skip non-compiling/unsupported
    // stage the runnable copy (debug-off, no legal footer)
    fs.writeFileSync(probe, stripCopyright(stripDebug(source)) + "\n");
    stagedNames.add(name);
    const url = "/docs/reference/programs/" + name;
    injected++; examplesWired++;
    return full + liveWidget(url, canvasHeight(source), usesDebug(source));
  });

  if (injected) {
    h = h.replace(/<\/body>/i, liveScript + "</body>");
    fs.writeFileSync(fp, h);
    pagesWired++;
  } else if (h !== fs.readFileSync(fp, "utf8")) {
    fs.writeFileSync(fp, h);   // persisted an unwire (had stale widgets, now none qualify)
  }
}

// remove stale staged programs from prior runs that no page references anymore
for (const e of fs.readdirSync(PROGRAMS)) {
  if (e.endsWith(".lzx") && !stagedNames.has(e)) fs.rmSync(path.join(PROGRAMS, e));
}

console.log(`reference: wired ${examplesWired} live examples across ${pagesWired} pages ` +
  `(${candidates} <canvas> candidates, ${skipped} skipped by compile-gate).`);
